#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

#define WIDTH 800
#define HEIGHT 600
#define MAX_DIST 100.0f
#define EPSILON 0.001f

// Vec3 operations
void normalize(float *v) {
    float len = sqrtf(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]);
    v[0] /= len; v[1] /= len; v[2] /= len;
}

void sub(float *r, float *a, float *b) {
    r[0] = a[0] - b[0]; r[1] = a[1] - b[1]; r[2] = a[2] - b[2];
}

void add(float *r, float *a, float *b) {
    r[0] = a[0] + b[0]; r[1] = a[1] + b[1]; r[2] = a[2] + b[2];
}

void mul(float *r, float *a, float s) {
    r[0] = a[0] * s; r[1] = a[1] * s; r[2] = a[2] * s;
}

float dot(float *a, float *b) {
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2];
}

// Sphere intersection: returns t (distance), 0 if miss
float sphere_intersect(float *ro, float *rd, float *center, float radius, float *hit_pos, float *hit_normal) {
    float oc[3];
    sub(oc, ro, center);
    float a = dot(rd, rd);
    float b = 2.0f * dot(oc, rd);
    float c = dot(oc, oc) - radius * radius;
    float disc = b*b - 4.0f*a*c;
    if (disc < 0) return 0;
    float t = (-b - sqrtf(disc)) / (2.0f * a);
    if (t < EPSILON) {
        t = (-b + sqrtf(disc)) / (2.0f * a);
        if (t < EPSILON) return 0;
    }
    hit_pos[0] = ro[0] + rd[0]*t;
    hit_pos[1] = ro[1] + rd[1]*t;
    hit_pos[2] = ro[2] + rd[2]*t;
    sub(hit_normal, hit_pos, center);
    normalize(hit_normal);
    return t;
}

// Plane intersection: y = 0
float plane_intersect(float *ro, float *rd, float *hit_pos, float *hit_normal) {
    if (rd[1] >= 0) return 0;
    float t = -ro[1] / rd[1];
    if (t < EPSILON) return 0;
    hit_pos[0] = ro[0] + rd[0]*t;
    hit_pos[1] = 0;
    hit_pos[2] = ro[2] + rd[2]*t;
    hit_normal[0] = 0; hit_normal[1] = 1; hit_normal[2] = 0;
    return t;
}

int main() {
    float *image = (float*)malloc(WIDTH * HEIGHT * 3 * sizeof(float));

    // Camera
    float cam_pos[] = {0, 0, -1.5f};
    float cam_dir[] = {0, 0, 1};
    float cam_up[] = {0, 1, 0};
    float aspect = (float)WIDTH / HEIGHT;

    // Sphere
    float sphere_center[] = {0, 0.5f, 0};
    float sphere_radius = 0.5f;
    float sphere_color[] = {0.8f, 0.2f, 0.2f};

    // Light
    float light_pos[] = {2, 3, 2};
    float light_color[] = {1, 1, 1};
    float ambient = 0.1f;

    fprintf(stderr, "Progress: %.1f%%\r", 0.0f);

    int idx = 0;
    for (int y = 0; y < HEIGHT; y++) {
        for (int x = 0; x < WIDTH; x++) {
            // Generate ray
            float ndc_x = (2.0f * (x + 0.5f) / WIDTH - 1.0f) * aspect;
            float ndc_y = 1.0f - 2.0f * (y + 0.5f) / HEIGHT;

            float rd[3] = {ndc_x, ndc_y, 1.0f};
            normalize(rd);
            float ro[3] = {0, 0, -1.5f};

            float final_color[3] = {0, 0, 0};

            // Trace sphere
            float hit_pos[3], hit_normal[3];
            float t = sphere_intersect(ro, rd, sphere_center, sphere_radius, hit_pos, hit_normal);

            if (t > 0) {
                // Lighting
                float light_dir[3];
                sub(light_dir, light_pos, hit_pos);
                normalize(light_dir);
                float diff = fmaxf(0, dot(hit_normal, light_dir));

                // Specular (Blinn-Phong)
                float view_dir[3];
                sub(view_dir, ro, hit_pos);
                normalize(view_dir);
                float half_dir[3];
                add(half_dir, light_dir, view_dir);
                normalize(half_dir);
                float spec = powf(fmaxf(0, dot(hit_normal, half_dir)), 20.0f);

                final_color[0] = sphere_color[0] * (ambient + diff * 0.7f) + spec * 0.5f;
                final_color[1] = sphere_color[1] * (ambient + diff * 0.7f) + spec * 0.5f;
                final_color[2] = sphere_color[2] * (ambient + diff * 0.7f) + spec * 0.5f;
            } else {
                // Check plane (ground)
                float hit_pos2[3], hit_normal2[3];
                t = plane_intersect(ro, rd, hit_pos2, hit_normal2);
                if (t > 0 && t < MAX_DIST) {
                    // Ground: checkerboard or gradient
                    float px = hit_pos2[0];
                    float pz = hit_pos2[2];
                    float pattern = fabs(fmod(floor(px) + floor(pz), 2.0f));
                    if (pattern < 0.5) {
                        final_color[0] = 0.6f;
                        final_color[1] = 0.6f;
                        final_color[2] = 0.6f;
                    } else {
                        final_color[0] = 0.2f;
                        final_color[1] = 0.2f;
                        final_color[2] = 0.2f;
                    }
                    // Ground gradient based on distance
                    float dist = sqrtf(hit_pos2[0]*hit_pos2[0] + hit_pos2[2]*hit_pos2[2]);
                    float fog = fminf(1, dist * 0.1f);
                    final_color[0] = final_color[0] * (1-fog) + 0.6f * fog;
                    final_color[1] = final_color[1] * (1-fog) + 0.6f * fog;
                    final_color[2] = final_color[2] * (1-fog) + 0.6f * fog;
                } else {
                    // Sky: blue gradient
                    float t = fmaxf(0, (rd[1] + 0.3f) / 1.3f);
                    final_color[0] = 0.6f + t * 0.2f;
                    final_color[1] = 0.75f + t * 0.1f;
                    final_color[2] = 1.0f;
                }
            }

            // Clamp and store
            image[idx++] = fmaxf(0, fminf(1, final_color[0]));
            image[idx++] = fmaxf(0, fminf(1, final_color[1]));
            image[idx++] = fmaxf(0, fminf(1, final_color[2]));
        }

        if (y % 60 == 0) {
            fprintf(stderr, "\rProgress: %.1f%%", 100.0f * y / HEIGHT);
        }
    }

    fprintf(stderr, "\rProgress: 99.8%%\n");
    fprintf(stderr, "Rendering complete\n");

    // Write PPM
    FILE *fp = fopen("image.ppm", "w");
    fprintf(fp, "P3\n%d %d\n255\n", WIDTH, HEIGHT);
    for (int i = 0; i < WIDTH * HEIGHT * 3; i += 3) {
        int r = (int)(image[i] * 255.99f);
        int g = (int)(image[i+1] * 255.99f);
        int b = (int)(image[i+2] * 255.99f);
        fprintf(fp, "%d %d %d\n", r, g, b);
    }
    fclose(fp);

    fprintf(stderr, "Wrote image to image.ppm\n");
    fprintf(stderr, "Done.\n");

    free(image);
    return 0;
}
EOF
